import scala.sys.process._
import scala.util.{Try, Success, Failure}
import java.io.File
import java.util.concurrent.TimeUnit
import scala.concurrent.duration._
import scala.concurrent.{Future, Await, TimeoutException}
import scala.concurrent.ExecutionContext.Implicits.global

case class CommandRequest(
  command: String,
  args: List[String] = List.empty,
  workingDir: Option[String] = None,
  env: Map[String, String] = Map.empty,
  timeout: Option[Int] = None
)

case class CommandResult(
  exitCode: Int,
  stdout: String,
  stderr: String,
  success: Boolean
)

case class CommandException(message: String, cause: Throwable = null) extends Exception(message, cause)

class SystemAdminService {

  private val allowedCommands = Set(
    "ls", "cat", "grep", "find", "df", "du", "ps", "top", "netstat",
    "systemctl", "journalctl", "docker", "kubectl", "git", "mvn",
    "sbt", "npm", "yarn", "curl", "wget", "tar", "gzip", "zip",
    "chmod", "chown", "mkdir", "rm", "cp", "mv", "touch", "echo"
  )

  def executeCommand(request: CommandRequest): CommandResult = {
    validateCommand(request.command)
    
    val fullCommand = buildCommand(request.command, request.args)
    val processBuilder = buildProcess(fullCommand, request.workingDir, request.env)
    
    request.timeout match {
      case Some(timeoutSeconds) => executeWithTimeout(processBuilder, timeoutSeconds)
      case None => executeProcess(processBuilder)
    }
  }

  def executeCommandAsync(request: CommandRequest): Future[CommandResult] = Future {
    executeCommand(request)
  }

  def executeRawCommand(command: String, userInput: String): String = {
    validateCommand(command)
    val sanitizedInput = sanitizeInput(userInput)
    s"$command $sanitizedInput".!!
  }

  def executeRawCommandWithArgs(command: String, args: List[String]): String = {
    validateCommand(command)
    val sanitizedArgs = args.map(sanitizeInput)
    val fullCommand = s"$command ${sanitizedArgs.mkString(" ")}"
    fullCommand.!!
  }

  def executePipedCommands(commands: List[CommandRequest]): CommandResult = {
    if (commands.isEmpty) {
      throw CommandException("No commands provided")
    }

    commands.foreach(cmd => validateCommand(cmd.command))

    val processes = commands.map { cmd =>
      val fullCommand = buildCommand(cmd.command, cmd.args)
      Process(fullCommand, cmd.workingDir.map(new File(_)), cmd.env.toSeq: _*)
    }

    val pipedProcess = processes.reduceLeft(_ #| _)
    executeProcess(pipedProcess)
  }

  def executeWithRedirect(request: CommandRequest, outputFile: String): CommandResult = {
    validateCommand(request.command)
    
    val fullCommand = buildCommand(request.command, request.args)
    val process = Process(fullCommand, request.workingDir.map(new File(_)), request.env.toSeq: _*)
    val redirected = process #> new File(outputFile)
    
    executeProcess(redirected)
  }

  def executeWithInputRedirect(request: CommandRequest, inputFile: String): CommandResult = {
    validateCommand(request.command)
    
    val fullCommand = buildCommand(request.command, request.args)
    val process = Process(fullCommand, request.workingDir.map(new File(_)), request.env.toSeq: _*)
    val redirected = process #< new File(inputFile)
    
    executeProcess(redirected)
  }

  def executeBatch(requests: List[CommandRequest]): List[CommandResult] = {
    requests.map(executeCommand)
  }

  def executeBatchAsync(requests: List[CommandRequest]): Future[List[CommandResult]] = {
    Future.sequence(requests.map(executeCommandAsync))
  }

  def executeChained(requests: List[CommandRequest]): List[CommandResult] = {
    val results = scala.collection.mutable.ListBuffer[CommandResult]()
    
    for (request <- requests) {
      val result = executeCommand(request)
      results += result
      
      if (!result.success) {
        return results.toList
      }
    }
    
    results.toList
  }

  private def validateCommand(command: String): Unit = {
    val baseCommand = command.split("\\s+").headOption.getOrElse("")
    
    if (baseCommand.isEmpty) {
      throw CommandException("Command cannot be empty")
    }
    
    if (!allowedCommands.contains(baseCommand)) {
      throw CommandException(s"Command '$baseCommand' is not in the allowed list")
    }
    
    if (command.contains("&&") || command.contains("||") || command.contains(";") || 
        command.contains("|") || command.contains(">") || command.contains("<")) {
      throw CommandException("Command contains forbidden operators")
    }
  }

  private def sanitizeInput(input: String): String = {
    input
      .replaceAll("[;&|<>$`\\\\]", "")
      .replaceAll("\\.\\.+", "")
      .trim
  }

  private def buildCommand(command: String, args: List[String]): Seq[String] = {
    val sanitizedArgs = args.map(sanitizeInput)
    command +: sanitizedArgs
  }

  private def buildProcess(command: Seq[String], workingDir: Option[String], env: Map[String, String]): ProcessBuilder = {
    val dir = workingDir.map(new File(_))
    Process(command, dir, env.toSeq: _*)
  }

  private def executeProcess(process: ProcessBuilder): CommandResult = {
    val stdout = new StringBuilder
    val stderr = new StringBuilder
    
    val logger = ProcessLogger(
      line => stdout.append(line).append("\n"),
      line => stderr.append(line).append("\n")
    )
    
    Try(process.!(logger)) match {
      case Success(exitCode) =>
        CommandResult(
          exitCode = exitCode,
          stdout = stdout.toString.trim,
          stderr = stderr.toString.trim,
          success = exitCode == 0
        )
      case Failure(exception) =>
        CommandResult(
          exitCode = -1,
          stdout = stdout.toString.trim,
          stderr = stderr.toString.trim + "\n" + exception.getMessage,
          success = false
        )
    }
  }

  private def executeWithTimeout(process: ProcessBuilder, timeoutSeconds: Int): CommandResult = {
    val future = Future {
      executeProcess(process)
    }
    
    Try(Await.result(future, timeoutSeconds.seconds)) match {
      case Success(result) => result
      case Failure(_: TimeoutException) =>
        CommandResult(
          exitCode = -1,
          stdout = "",
          stderr = s"Command timed out after $timeoutSeconds seconds",
          success = false
        )
      case Failure(exception) =>
        CommandResult(
          exitCode = -1,
          stdout = "",
          stderr = exception.getMessage,
          success = false
        )
    }
  }
}

object SystemAdminAPI {
  
  val service = new SystemAdminService()
  
  def handleListFiles(path: String): CommandResult = {
    service.executeCommand(CommandRequest("ls", List("-la", path)))
  }
  
  def handleFindFiles(directory: String, pattern: String): CommandResult = {
    service.executeCommand(CommandRequest("find", List(directory, "-name", pattern)))
  }
  
  def handleDiskUsage(path: String): CommandResult = {
    service.executeCommand(CommandRequest("du", List("-sh", path)))
  }
  
  def handleProcessList(filter: String): CommandResult = {
    service.executePipedCommands(List(
      CommandRequest("ps", List("aux")),
      CommandRequest("grep", List(filter))
    ))
  }
  
  def handleDockerCommand(action: String, args: List[String]): CommandResult = {
    service.executeCommand(CommandRequest("docker", action :: args))
  }
  
  def handleSystemctlCommand(action: String, serviceName: String): CommandResult = {
    service.executeCommand(CommandRequest("systemctl", List(action, serviceName)))
  }
  
  def handleGitCommand(repoPath: String, gitArgs: List[String]): CommandResult = {
    service.executeCommand(CommandRequest("git", gitArgs, Some(repoPath)))
  }
  
  def handleCustomCommand(request: CommandRequest): CommandResult = {
    service.executeCommand(request)
  }
  
  def handleBatchCommands(requests: List[CommandRequest]): List[CommandResult] = {
    service.executeBatch(requests)
  }
}

